import { useState, useEffect, useMemo, useCallback } from "react";
import { useQuery } from "@tanstack/react-query";
import { useTranslation } from "react-i18next";
import { format, subDays, startOfDay, endOfDay, differenceInDays } from "date-fns";
import { Card, CardContent, CardHeader, CardTitle } from "@/components/ui/card";
import { Button } from "@/components/ui/button";
import { Badge } from "@/components/ui/badge";
import { Skeleton } from "@/components/ui/skeleton";
import { Calendar } from "@/components/ui/calendar";
import { Popover, PopoverContent, PopoverTrigger } from "@/components/ui/popover";
import { Switch } from "@/components/ui/switch";
import { Label } from "@/components/ui/label";
import { Progress } from "@/components/ui/progress";
import { cn } from "@/lib/utils";
import {
  Calendar as CalendarIcon, RefreshCw, TrendingUp, TrendingDown,
  Ticket, Users, Bot, Mail, ChefHat, Video, MessageCircle,
} from "lucide-react";
import { supabase } from "@/integrations/supabase/client";
import {
  ResponsiveContainer, LineChart, Line, XAxis, YAxis, CartesianGrid, Tooltip,
  PieChart, Pie, Cell, BarChart, Bar, Legend,
} from "recharts";

const COLORS = ['hsl(var(--primary))', 'hsl(var(--chart-2))', 'hsl(var(--chart-3))', 'hsl(var(--chart-4))', 'hsl(var(--chart-5))', 'hsl(var(--muted-foreground))'];

type InsightsData = {
  coupons: { claimed: number; redeemed: number; claimed_prev: number; redeemed_prev: number; top: any[] };
  users: { total: number; new: number; new_prev: number; merchant_total: number; role_distribution: { role: string; count: number }[] };
  ai: { chat_total: number; chat_prev: number; chat_by_type: { type: string; count: number }[]; recipe: number; recipe_prev: number; video: number; video_prev: number; daily: { date: string; chats: number }[] };
  email: { period_success: number; period_failed: number; period_total: number; period_jobs: number; recent_jobs: any[] };
};

function pctChange(curr: number, prev: number): number | null {
  if (prev === 0) return curr > 0 ? 100 : null;
  return ((curr - prev) / prev) * 100;
}

function DeltaBadge({ curr, prev }: { curr: number; prev: number }) {
  const delta = pctChange(curr, prev);
  if (delta === null) return <span className="text-xs text-muted-foreground">—</span>;
  const up = delta >= 0;
  const Icon = up ? TrendingUp : TrendingDown;
  return (
    <span className={cn("inline-flex items-center gap-0.5 text-xs font-medium", up ? "text-success" : "text-destructive")}>
      <Icon className="h-3 w-3" />
      {Math.abs(delta).toFixed(1)}%
    </span>
  );
}

function KpiCard({ title, value, prev, icon: Icon, suffix }: { title: string; value: number; prev: number; icon: any; suffix?: string }) {
  return (
    <Card>
      <CardHeader className="flex flex-row items-center justify-between pb-2">
        <CardTitle className="text-sm font-medium">{title}</CardTitle>
        <Icon className="h-4 w-4 text-muted-foreground" />
      </CardHeader>
      <CardContent>
        <div className="flex items-baseline gap-2">
          <div className="text-2xl font-bold">{value.toLocaleString()}{suffix}</div>
          <DeltaBadge curr={value} prev={prev} />
        </div>
        <p className="text-xs text-muted-foreground mt-1">vs {prev.toLocaleString()}{suffix}</p>
      </CardContent>
    </Card>
  );
}

const BusinessInsights = () => {
  const { t, i18n } = useTranslation();
  const lang = i18n.language;
  const [endDate, setEndDate] = useState<Date>(new Date());
  const [startDate, setStartDate] = useState<Date>(subDays(new Date(), 6));
  const [autoRefresh, setAutoRefresh] = useState(false);

  const { startISO, endISO, prevStartISO, prevEndISO, daySpan } = useMemo(() => {
    const s = startOfDay(startDate);
    const e = endOfDay(endDate);
    const span = Math.max(1, differenceInDays(e, s) + 1);
    const prevEnd = startOfDay(s);
    const prevStart = subDays(prevEnd, span);
    return {
      startISO: s.toISOString(),
      endISO: e.toISOString(),
      prevStartISO: prevStart.toISOString(),
      prevEndISO: prevEnd.toISOString(),
      daySpan: span,
    };
  }, [startDate, endDate]);

  const { data, isLoading, refetch, isRefetching } = useQuery({
    queryKey: ["business-insights", startISO, endISO],
    queryFn: async () => {
      const { data, error } = await supabase.rpc("get_business_insights", {
        p_start: startISO,
        p_end: endISO,
        p_prev_start: prevStartISO,
        p_prev_end: prevEndISO,
      });
      if (error) throw error;
      return data as unknown as InsightsData;
    },
  });

  useEffect(() => {
    if (!autoRefresh) return;
    const id = setInterval(() => refetch(), 30000);
    return () => clearInterval(id);
  }, [autoRefresh, refetch]);

  const setQuickRange = useCallback((days: number) => {
    setEndDate(new Date());
    setStartDate(subDays(new Date(), days - 1));
  }, []);

  const couponRate = useMemo(() => {
    if (!data?.coupons) return 0;
    return data.coupons.claimed > 0 ? (data.coupons.redeemed / data.coupons.claimed) * 100 : 0;
  }, [data?.coupons]);

  const couponRatePrev = useMemo(() => {
    if (!data?.coupons) return 0;
    return data.coupons.claimed_prev > 0 ? (data.coupons.redeemed_prev / data.coupons.claimed_prev) * 100 : 0;
  }, [data?.coupons]);

  const roleData = data?.users.role_distribution.map(r => ({ name: t(`admin.businessInsights.roles.${r.role}`, r.role), value: r.count })) || [];
  const chatTypeData = data?.ai.chat_by_type.map(c => ({ name: c.type, value: c.count })) || [];

  if (isLoading) {
    return (
      <div className="space-y-4">
        <Skeleton className="h-12 w-full" />
        <div className="grid grid-cols-1 md:grid-cols-4 gap-4">
          {[...Array(4)].map((_, i) => <Skeleton key={i} className="h-28" />)}
        </div>
      </div>
    );
  }

  return (
    <div className="space-y-6">
      {/* Toolbar */}
      <Card>
        <CardContent className="pt-6 flex flex-wrap items-center gap-3">
          <div className="flex gap-1 flex-wrap">
            {[1, 7, 30, 90].map(d => (
              <Button key={d} size="sm" variant="outline" onClick={() => setQuickRange(d)}>
                {d === 1 ? t("admin.businessInsights.today", "今日") : `${d}${t("analytics.days", "天")}`}
              </Button>
            ))}
          </div>
          <Popover>
            <PopoverTrigger asChild>
              <Button variant="outline" size="sm" className="gap-2">
                <CalendarIcon className="h-4 w-4" />
                {format(startDate, "yyyy/MM/dd")} - {format(endDate, "yyyy/MM/dd")}
              </Button>
            </PopoverTrigger>
            <PopoverContent className="w-auto p-0 pointer-events-auto" align="start">
              <Calendar
                mode="range"
                defaultMonth={startDate}
                selected={{ from: startDate, to: endDate }}
                onSelect={(r) => { if (r?.from) setStartDate(r.from); if (r?.to) setEndDate(r.to); }}
                numberOfMonths={2}
                className="p-3 pointer-events-auto"
              />
            </PopoverContent>
          </Popover>
          <Badge variant="secondary">{daySpan} {t("admin.businessInsights.days", "天")}</Badge>
          <div className="ml-auto flex items-center gap-3">
            <div className="flex items-center gap-2">
              <Switch id="auto-refresh" checked={autoRefresh} onCheckedChange={setAutoRefresh} />
              <Label htmlFor="auto-refresh" className="text-sm">{t("admin.businessInsights.autoRefresh", "实时刷新")}</Label>
            </div>
            <Button variant="outline" size="sm" onClick={() => refetch()} disabled={isRefetching}>
              <RefreshCw className={cn("h-4 w-4 mr-1", isRefetching && "animate-spin")} />
              {t("common.refresh", "刷新")}
            </Button>
          </div>
        </CardContent>
      </Card>

      {/* Coupons */}
      <section className="space-y-3">
        <h2 className="text-xl font-semibold flex items-center gap-2"><Ticket className="h-5 w-5" />{t("admin.businessInsights.coupons.title", "优惠券核销")}</h2>
        <div className="grid grid-cols-1 md:grid-cols-4 gap-4">
          <KpiCard title={t("admin.businessInsights.coupons.claimed", "本期领取")} value={data?.coupons.claimed || 0} prev={data?.coupons.claimed_prev || 0} icon={Ticket} />
          <KpiCard title={t("admin.businessInsights.coupons.redeemed", "本期核销")} value={data?.coupons.redeemed || 0} prev={data?.coupons.redeemed_prev || 0} icon={Ticket} />
          <Card>
            <CardHeader className="flex flex-row items-center justify-between pb-2">
              <CardTitle className="text-sm font-medium">{t("admin.businessInsights.coupons.rate", "核销率")}</CardTitle>
              <TrendingUp className="h-4 w-4 text-muted-foreground" />
            </CardHeader>
            <CardContent>
              <div className="flex items-baseline gap-2">
                <div className="text-2xl font-bold">{couponRate.toFixed(1)}%</div>
                <DeltaBadge curr={couponRate} prev={couponRatePrev} />
              </div>
              <Progress value={couponRate} className="h-2 mt-2" />
            </CardContent>
          </Card>
          <Card>
            <CardHeader className="pb-2"><CardTitle className="text-sm font-medium">{t("admin.businessInsights.coupons.activeTemplates", "活跃模板")}</CardTitle></CardHeader>
            <CardContent>
              <div className="text-2xl font-bold">{data?.coupons.top.filter(t => t.redeemed > 0).length || 0}</div>
              <p className="text-xs text-muted-foreground mt-1">{t("admin.businessInsights.coupons.topRedeem", "本期有核销")}</p>
            </CardContent>
          </Card>
        </div>
        {data?.coupons.top && data.coupons.top.length > 0 && (
          <Card>
            <CardHeader><CardTitle className="text-base">{t("admin.businessInsights.coupons.topTitle", "Top 10 优惠券模板核销排行")}</CardTitle></CardHeader>
            <CardContent>
              <div className="space-y-2">
                {data.coupons.top.map((c: any) => {
                  const title = lang === "en" ? c.title_en : lang === "pt" ? c.title_pt : c.title_zh;
                  const max = data.coupons.top[0]?.redeemed || 1;
                  return (
                    <div key={c.id} className="flex items-center gap-3">
                      <div className="w-48 truncate text-sm">{title || c.title_zh}</div>
                      <div className="flex-1 bg-muted rounded h-6 relative overflow-hidden">
                        <div className="bg-primary h-full transition-all" style={{ width: `${Math.max(2, (c.redeemed / max) * 100)}%` }} />
                      </div>
                      <div className="w-16 text-right text-sm font-mono">{c.redeemed}</div>
                    </div>
                  );
                })}
              </div>
            </CardContent>
          </Card>
        )}
      </section>

      {/* Users & Merchants */}
      <section className="space-y-3">
        <h2 className="text-xl font-semibold flex items-center gap-2"><Users className="h-5 w-5" />{t("admin.businessInsights.users.title", "商家与会员")}</h2>
        <div className="grid grid-cols-1 md:grid-cols-4 gap-4">
          <Card>
            <CardHeader className="pb-2"><CardTitle className="text-sm font-medium">{t("admin.businessInsights.users.total", "用户总数")}</CardTitle></CardHeader>
            <CardContent><div className="text-2xl font-bold">{data?.users.total.toLocaleString() || 0}</div></CardContent>
          </Card>
          <KpiCard title={t("admin.businessInsights.users.new", "本期新增用户")} value={data?.users.new || 0} prev={data?.users.new_prev || 0} icon={Users} />
          <Card>
            <CardHeader className="pb-2"><CardTitle className="text-sm font-medium">{t("admin.businessInsights.users.merchants", "商家总数")}</CardTitle></CardHeader>
            <CardContent><div className="text-2xl font-bold">{data?.users.merchant_total.toLocaleString() || 0}</div></CardContent>
          </Card>
          <Card className="md:row-span-2">
            <CardHeader className="pb-2"><CardTitle className="text-sm font-medium">{t("admin.businessInsights.users.roleDist", "角色分布")}</CardTitle></CardHeader>
            <CardContent>
              <div className="h-[180px]">
                {roleData.length > 0 && (
                  <ResponsiveContainer width="100%" height="100%">
                    <PieChart>
                      <Pie data={roleData} dataKey="value" nameKey="name" outerRadius={70} label={({ name, percent }) => `${name} ${(percent * 100).toFixed(0)}%`}>
                        {roleData.map((_, i) => <Cell key={i} fill={COLORS[i % COLORS.length]} />)}
                      </Pie>
                      <Tooltip />
                    </PieChart>
                  </ResponsiveContainer>
                )}
              </div>
            </CardContent>
          </Card>
        </div>
      </section>

      {/* AI Usage */}
      <section className="space-y-3">
        <h2 className="text-xl font-semibold flex items-center gap-2"><Bot className="h-5 w-5" />{t("admin.businessInsights.ai.title", "AI 助手使用")}</h2>
        <div className="grid grid-cols-1 md:grid-cols-3 gap-4">
          <KpiCard title={t("admin.businessInsights.ai.chats", "对话总数")} value={data?.ai.chat_total || 0} prev={data?.ai.chat_prev || 0} icon={MessageCircle} />
          <KpiCard title={t("admin.businessInsights.ai.recipes", "AI 食谱生成")} value={data?.ai.recipe || 0} prev={data?.ai.recipe_prev || 0} icon={ChefHat} />
          <KpiCard title={t("admin.businessInsights.ai.videos", "AI 视频生成")} value={data?.ai.video || 0} prev={data?.ai.video_prev || 0} icon={Video} />
        </div>
        <div className="grid grid-cols-1 lg:grid-cols-3 gap-4">
          <Card className="lg:col-span-2">
            <CardHeader><CardTitle className="text-base">{t("admin.businessInsights.ai.dailyTrend", "AI 对话日趋势")}</CardTitle></CardHeader>
            <CardContent>
              <div className="h-[260px]">
                {data?.ai.daily && data.ai.daily.length > 0 ? (
                  <ResponsiveContainer width="100%" height="100%">
                    <LineChart data={data.ai.daily}>
                      <CartesianGrid strokeDasharray="3 3" className="stroke-muted" />
                      <XAxis dataKey="date" tickFormatter={(v) => format(new Date(v), "MM/dd")} className="text-xs" />
                      <YAxis className="text-xs" />
                      <Tooltip contentStyle={{ backgroundColor: "hsl(var(--background))", border: "1px solid hsl(var(--border))" }} />
                      <Line type="monotone" dataKey="chats" stroke="hsl(var(--primary))" strokeWidth={2} />
                    </LineChart>
                  </ResponsiveContainer>
                ) : <div className="h-full flex items-center justify-center text-muted-foreground">{t("analytics.noData", "暂无数据")}</div>}
              </div>
            </CardContent>
          </Card>
          <Card>
            <CardHeader><CardTitle className="text-base">{t("admin.businessInsights.ai.byType", "按对话类型")}</CardTitle></CardHeader>
            <CardContent>
              <div className="h-[260px]">
                {chatTypeData.length > 0 ? (
                  <ResponsiveContainer width="100%" height="100%">
                    <BarChart data={chatTypeData} layout="vertical">
                      <CartesianGrid strokeDasharray="3 3" className="stroke-muted" />
                      <XAxis type="number" className="text-xs" />
                      <YAxis dataKey="name" type="category" width={100} className="text-xs" />
                      <Tooltip contentStyle={{ backgroundColor: "hsl(var(--background))", border: "1px solid hsl(var(--border))" }} />
                      <Bar dataKey="value" fill="hsl(var(--primary))" />
                    </BarChart>
                  </ResponsiveContainer>
                ) : <div className="h-full flex items-center justify-center text-muted-foreground">{t("analytics.noData", "暂无数据")}</div>}
              </div>
            </CardContent>
          </Card>
        </div>
      </section>

      {/* Email Marketing */}
      <section className="space-y-3">
        <h2 className="text-xl font-semibold flex items-center gap-2"><Mail className="h-5 w-5" />{t("admin.businessInsights.email.title", "邮件营销效果")}</h2>
        <div className="grid grid-cols-1 md:grid-cols-4 gap-4">
          <Card>
            <CardHeader className="pb-2"><CardTitle className="text-sm font-medium">{t("admin.businessInsights.email.jobs", "本期任务数")}</CardTitle></CardHeader>
            <CardContent><div className="text-2xl font-bold">{data?.email.period_jobs || 0}</div></CardContent>
          </Card>
          <Card>
            <CardHeader className="pb-2"><CardTitle className="text-sm font-medium">{t("admin.businessInsights.email.totalSent", "本期发送总量")}</CardTitle></CardHeader>
            <CardContent><div className="text-2xl font-bold">{data?.email.period_total || 0}</div></CardContent>
          </Card>
          <Card>
            <CardHeader className="pb-2"><CardTitle className="text-sm font-medium">{t("admin.businessInsights.email.success", "成功")}</CardTitle></CardHeader>
            <CardContent><div className="text-2xl font-bold text-success">{data?.email.period_success || 0}</div></CardContent>
          </Card>
          <Card>
            <CardHeader className="pb-2"><CardTitle className="text-sm font-medium">{t("admin.businessInsights.email.successRate", "成功率")}</CardTitle></CardHeader>
            <CardContent>
              <div className="text-2xl font-bold">
                {data?.email.period_total ? ((data.email.period_success / data.email.period_total) * 100).toFixed(1) : "0.0"}%
              </div>
              <Progress value={data?.email.period_total ? (data.email.period_success / data.email.period_total) * 100 : 0} className="h-2 mt-2" />
            </CardContent>
          </Card>
        </div>
        {data?.email.recent_jobs && data.email.recent_jobs.length > 0 && (
          <Card>
            <CardHeader><CardTitle className="text-base">{t("admin.businessInsights.email.recent", "最近 10 个群发任务")}</CardTitle></CardHeader>
            <CardContent>
              <div className="overflow-x-auto">
                <table className="w-full text-sm">
                  <thead className="text-xs text-muted-foreground border-b">
                    <tr>
                      <th className="text-left py-2">{t("admin.businessInsights.email.subject", "主题")}</th>
                      <th className="text-right py-2">{t("admin.businessInsights.email.total", "总数")}</th>
                      <th className="text-right py-2">{t("admin.businessInsights.email.success", "成功")}</th>
                      <th className="text-right py-2">{t("admin.businessInsights.email.failed", "失败")}</th>
                      <th className="text-right py-2">{t("admin.businessInsights.email.successRate", "成功率")}</th>
                      <th className="text-right py-2">{t("admin.businessInsights.email.status", "状态")}</th>
                      <th className="text-right py-2">{t("admin.businessInsights.email.time", "时间")}</th>
                    </tr>
                  </thead>
                  <tbody>
                    {data.email.recent_jobs.map((j: any) => {
                      const rate = j.total_count ? (j.success_count / j.total_count) * 100 : 0;
                      return (
                        <tr key={j.id} className="border-b last:border-b-0">
                          <td className="py-2 truncate max-w-[280px]">{j.subject}</td>
                          <td className="text-right">{j.total_count}</td>
                          <td className="text-right text-success">{j.success_count}</td>
                          <td className="text-right text-destructive">{j.failed_count}</td>
                          <td className="text-right font-mono">{rate.toFixed(1)}%</td>
                          <td className="text-right"><Badge variant={j.status === "completed" ? "default" : "secondary"}>{j.status}</Badge></td>
                          <td className="text-right text-xs text-muted-foreground">{format(new Date(j.created_at), "MM/dd HH:mm")}</td>
                        </tr>
                      );
                    })}
                  </tbody>
                </table>
              </div>
            </CardContent>
          </Card>
        )}
      </section>
    </div>
  );
};

export default BusinessInsights;
